CREATE EXTENSION IF NOT EXISTS "uuid-ossp";CREATE TABLE organizations(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),name text NOT NULL,created_at timestamp with time zone DEFAULT now() NOT NULL);ALTER TABLE organizations ENABLE ROW LEVEL SECURITY;CREATE POLICY "Admins can manage organizations" ON organizations FOR ALL USING ((SELECT role FROM profiles WHERE id = auth.uid()) = 'admin') WITH CHECK ((SELECT role FROM profiles WHERE id = auth.uid()) = 'admin');CREATE POLICY "Authenticated users can view organizations" ON organizations FOR SELECT USING (auth.uid() IS NOT NULL);CREATE TABLE profiles(id uuid PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,organization_id uuid REFERENCES organizations(id) ON DELETE CASCADE NOT NULL,full_name text,role text NOT NULL DEFAULT 'viewer',created_at timestamp with time zone DEFAULT now() NOT NULL,updated_at timestamp with time zone DEFAULT now() NOT NULL);CREATE INDEX idx_profiles_organization_id ON profiles(organization_id);ALTER TABLE profiles ENABLE ROW LEVEL SECURITY;CREATE POLICY "Users can view their own profile" ON profiles FOR SELECT USING (auth.uid() = id);CREATE POLICY "Users can update their own profile" ON profiles FOR UPDATE USING (auth.uid() = id);CREATE POLICY "Admins can view all profiles in their org" ON profiles FOR SELECT USING (organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin');CREATE POLICY "Admins can update profiles in their org" ON profiles FOR UPDATE USING (organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin');CREATE POLICY "Admins can insert profiles in their org" ON profiles FOR INSERT WITH CHECK (organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin');CREATE TABLE suppliers(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),organization_id uuid REFERENCES organizations(id) ON DELETE CASCADE NOT NULL,name text NOT NULL,contact_person text,contact_email text,phone text,address text,website text,payment_details jsonb,risk_assessment text,created_at timestamp with time zone DEFAULT now() NOT NULL,updated_at timestamp with time zone DEFAULT now() NOT NULL);CREATE INDEX idx_suppliers_organization_id ON suppliers(organization_id);ALTER TABLE suppliers ENABLE ROW LEVEL SECURITY;CREATE POLICY "Org members can view suppliers" ON suppliers FOR SELECT USING (organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()));CREATE POLICY "Org members can insert suppliers" ON suppliers FOR INSERT WITH CHECK (organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()));CREATE POLICY "Org members can update suppliers" ON suppliers FOR UPDATE USING (organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()));CREATE POLICY "Admins can delete suppliers" ON suppliers FOR DELETE USING (organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin');CREATE TABLE contracts(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),organization_id uuid REFERENCES organizations(id) ON DELETE CASCADE NOT NULL,supplier_id uuid REFERENCES suppliers(id) ON DELETE SET NULL,title text NOT NULL,contract_type text,start_date date,end_date date,value decimal(18, 2),currency text DEFAULT 'USD',payment_terms text,responsible_department text,status text NOT NULL DEFAULT 'Active',renewal_type text,renewal_notice_period_days integer,auto_renewal_clause_flagged boolean DEFAULT FALSE,next_action_date date,key_clauses jsonb,metadata jsonb,created_at timestamp with time zone DEFAULT now() NOT NULL,updated_at timestamp with time zone DEFAULT now() NOT NULL,created_by_user_id uuid REFERENCES auth.users(id) ON DELETE SET NULL,last_updated_by_user_id uuid REFERENCES auth.users(id) ON DELETE SET NULL);CREATE INDEX idx_contracts_organization_id ON contracts(organization_id);CREATE INDEX idx_contracts_supplier_id ON contracts(supplier_id);CREATE INDEX idx_contracts_status ON contracts(status);CREATE INDEX idx_contracts_end_date ON contracts(end_date);ALTER TABLE contracts ENABLE ROW LEVEL SECURITY;CREATE POLICY "Org members can view contracts" ON contracts FOR SELECT USING (organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()));CREATE POLICY "Org members can insert contracts" ON contracts FOR INSERT WITH CHECK (organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()));CREATE POLICY "Org members can update contracts" ON contracts FOR UPDATE USING (organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()));CREATE POLICY "Admins can delete contracts" ON contracts FOR DELETE USING (organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin');CREATE TABLE contract_documents(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),contract_id uuid REFERENCES contracts(id) ON DELETE CASCADE NOT NULL,file_url text NOT NULL,file_name text NOT NULL,file_type text,version integer DEFAULT 1 NOT NULL,is_main_document boolean DEFAULT FALSE,document_type text,uploaded_at timestamp with time zone DEFAULT now() NOT NULL,uploaded_by_user_id uuid REFERENCES auth.users(id) ON DELETE SET NULL,extracted_data jsonb);CREATE INDEX idx_contract_documents_contract_id ON contract_documents(contract_id);ALTER TABLE contract_documents ENABLE ROW LEVEL SECURITY;CREATE POLICY "Org members can view contract documents" ON contract_documents FOR SELECT USING (EXISTS (SELECT 1 FROM contracts WHERE id = contract_documents.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid())));CREATE POLICY "Org members can insert contract documents" ON contract_documents FOR INSERT WITH CHECK (EXISTS (SELECT 1 FROM contracts WHERE id = contract_documents.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid())));CREATE POLICY "Org members can update contract documents" ON contract_documents FOR UPDATE USING (EXISTS (SELECT 1 FROM contracts WHERE id = contract_documents.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid())));CREATE POLICY "Admins can delete contract documents" ON contract_documents FOR DELETE USING (EXISTS (SELECT 1 FROM contracts WHERE id = contract_documents.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin'));CREATE TABLE reminders(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),contract_id uuid REFERENCES contracts(id) ON DELETE CASCADE NOT NULL,reminder_date timestamp with time zone NOT NULL,message text NOT NULL,recipient_user_id uuid REFERENCES auth.users(id) ON DELETE SET NULL,notification_channels text[] DEFAULT ARRAY['in-app', 'email'],is_sent boolean DEFAULT FALSE,sent_at timestamp with time zone,created_at timestamp with time zone DEFAULT now() NOT NULL);CREATE INDEX idx_reminders_contract_id ON reminders(contract_id);CREATE INDEX idx_reminders_recipient_user_id ON reminders(recipient_user_id);ALTER TABLE reminders ENABLE ROW LEVEL SECURITY;CREATE POLICY "Users can view their own reminders" ON reminders FOR SELECT USING (recipient_user_id = auth.uid());CREATE POLICY "Org members can insert reminders for their org" ON reminders FOR INSERT WITH CHECK (EXISTS (SELECT 1 FROM contracts WHERE id = reminders.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid())));CREATE POLICY "Org members can update reminders for their org" ON reminders FOR UPDATE USING (EXISTS (SELECT 1 FROM contracts WHERE id = reminders.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid())));CREATE POLICY "Admins can delete reminders for their org" ON reminders FOR DELETE USING (EXISTS (SELECT 1 FROM contracts WHERE id = reminders.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin'));CREATE TABLE tasks(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),contract_id uuid REFERENCES contracts(id) ON DELETE CASCADE,assigned_to_user_id uuid REFERENCES auth.users(id) ON DELETE SET NULL,title text NOT NULL,description text,due_date date,status text NOT NULL DEFAULT 'Pending',priority text DEFAULT 'Medium',created_at timestamp with time zone DEFAULT now() NOT NULL,updated_at timestamp with time zone DEFAULT now() NOT NULL,created_by_user_id uuid REFERENCES auth.users(id) ON DELETE SET NULL);CREATE INDEX idx_tasks_contract_id ON tasks(contract_id);CREATE INDEX idx_tasks_assigned_to_user_id ON tasks(assigned_to_user_id);CREATE INDEX idx_tasks_status ON tasks(status);ALTER TABLE tasks ENABLE ROW LEVEL SECURITY;CREATE POLICY "Users can view their own tasks" ON tasks FOR SELECT USING (assigned_to_user_id = auth.uid() OR created_by_user_id = auth.uid());CREATE POLICY "Org members can insert tasks for their org" ON tasks FOR INSERT WITH CHECK (EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND organization_id = (SELECT organization_id FROM profiles WHERE id = tasks.assigned_to_user_id)));CREATE POLICY "Org members can update tasks for their org" ON tasks FOR UPDATE USING (assigned_to_user_id = auth.uid() OR created_by_user_id = auth.uid() OR EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND organization_id = (SELECT organization_id FROM profiles WHERE id = tasks.assigned_to_user_id) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin'));CREATE POLICY "Admins can delete tasks for their org" ON tasks FOR DELETE USING (EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND organization_id = (SELECT organization_id FROM profiles WHERE id = tasks.assigned_to_user_id) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin');CREATE TABLE approval_workflows(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),organization_id uuid REFERENCES organizations(id) ON DELETE CASCADE NOT NULL,name text NOT NULL,description text,workflow_type text NOT NULL,steps jsonb NOT NULL,created_at timestamp with time zone DEFAULT now() NOT NULL);CREATE INDEX idx_approval_workflows_organization_id ON approval_workflows(organization_id);ALTER TABLE approval_workflows ENABLE ROW LEVEL SECURITY;CREATE POLICY "Org members can view approval workflows" ON approval_workflows FOR SELECT USING (organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()));CREATE POLICY "Admins can manage approval workflows" ON approval_workflows FOR ALL USING (organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin');CREATE TABLE approval_requests(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),contract_id uuid REFERENCES contracts(id) ON DELETE CASCADE NOT NULL,workflow_id uuid REFERENCES approval_workflows(id) ON DELETE SET NULL,current_step_index integer DEFAULT 0 NOT NULL,status text NOT NULL DEFAULT 'Pending',requested_by_user_id uuid REFERENCES auth.users(id) ON DELETE SET NULL,created_at timestamp with time zone DEFAULT now() NOT NULL,updated_at timestamp with time zone DEFAULT now() NOT NULL);CREATE INDEX idx_approval_requests_contract_id ON approval_requests(contract_id);CREATE INDEX idx_approval_requests_requested_by_user_id ON approval_requests(requested_by_user_id);ALTER TABLE approval_requests ENABLE ROW LEVEL SECURITY;CREATE POLICY "Org members can view approval requests" ON approval_requests FOR SELECT USING (EXISTS (SELECT 1 FROM contracts WHERE id = approval_requests.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid())));CREATE POLICY "Org members can insert approval requests" ON approval_requests FOR INSERT WITH CHECK (EXISTS (SELECT 1 FROM contracts WHERE id = approval_requests.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid())));CREATE POLICY "Org members can update approval requests" ON approval_requests FOR UPDATE USING (EXISTS (SELECT 1 FROM contracts WHERE id = approval_requests.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid())));CREATE POLICY "Admins can delete approval requests" ON approval_requests FOR DELETE USING (EXISTS (SELECT 1 FROM contracts WHERE id = approval_requests.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin');CREATE TABLE approval_step_instances(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),approval_request_id uuid REFERENCES approval_requests(id) ON DELETE CASCADE NOT NULL,step_order integer NOT NULL,assigned_to_user_id uuid REFERENCES auth.users(id) ON DELETE SET NULL,status text NOT NULL DEFAULT 'Pending',comments text,completed_at timestamp with time zone,due_date date);CREATE INDEX idx_approval_step_instances_request_id ON approval_step_instances(approval_request_id);CREATE INDEX idx_approval_step_instances_assigned_to_user_id ON approval_step_instances(assigned_to_user_id);ALTER TABLE approval_step_instances ENABLE ROW LEVEL SECURITY;CREATE POLICY "Users can view their assigned approval steps" ON approval_step_instances FOR SELECT USING (assigned_to_user_id = auth.uid() OR EXISTS (SELECT 1 FROM approval_requests ar JOIN contracts c ON ar.contract_id = c.id WHERE ar.id = approval_step_instances.approval_request_id AND c.organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin'));CREATE POLICY "Users can update their assigned approval steps" ON approval_step_instances FOR UPDATE USING (assigned_to_user_id = auth.uid());CREATE POLICY "Org members can insert approval step instances" ON approval_step_instances FOR INSERT WITH CHECK (EXISTS (SELECT 1 FROM approval_requests ar JOIN contracts c ON ar.contract_id = c.id WHERE ar.id = approval_step_instances.approval_request_id AND c.organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid())));CREATE POLICY "Admins can delete approval step instances" ON approval_step_instances FOR DELETE USING (EXISTS (SELECT 1 FROM approval_requests ar JOIN contracts c ON ar.contract_id = c.id WHERE ar.id = approval_step_instances.approval_request_id AND c.organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin');CREATE TABLE supplier_performance(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),supplier_id uuid REFERENCES suppliers(id) ON DELETE CASCADE NOT NULL,contract_id uuid REFERENCES contracts(id) ON DELETE CASCADE,metric_name text NOT NULL,value text NOT NULL,date_recorded date NOT NULL,notes text,recorded_by_user_id uuid REFERENCES auth.users(id) ON DELETE SET NULL,created_at timestamp with time zone DEFAULT now() NOT NULL);CREATE INDEX idx_supplier_performance_supplier_id ON supplier_performance(supplier_id);CREATE INDEX idx_supplier_performance_contract_id ON supplier_performance(contract_id);ALTER TABLE supplier_performance ENABLE ROW LEVEL SECURITY;CREATE POLICY "Org members can view supplier performance" ON supplier_performance FOR SELECT USING (EXISTS (SELECT 1 FROM suppliers WHERE id = supplier_performance.supplier_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid())));CREATE POLICY "Org members can insert supplier performance" ON supplier_performance FOR INSERT WITH CHECK (EXISTS (SELECT 1 FROM suppliers WHERE id = supplier_performance.supplier_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid())));CREATE POLICY "Org members can update supplier performance" ON supplier_performance FOR UPDATE USING (EXISTS (SELECT 1 FROM suppliers WHERE id = supplier_performance.supplier_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid())));CREATE POLICY "Admins can delete supplier performance" ON supplier_performance FOR DELETE USING (EXISTS (SELECT 1 FROM suppliers WHERE id = supplier_performance.supplier_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin');CREATE TABLE communication_logs(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),contract_id uuid REFERENCES contracts(id) ON DELETE CASCADE,supplier_id uuid REFERENCES suppliers(id) ON DELETE CASCADE,user_id uuid REFERENCES auth.users(id) ON DELETE SET NULL,type text NOT NULL,subject text,body text,communication_date timestamp with time zone NOT NULL,created_at timestamp with time zone DEFAULT now() NOT NULL);CREATE INDEX idx_communication_logs_contract_id ON communication_logs(contract_id);CREATE INDEX idx_communication_logs_supplier_id ON communication_logs(supplier_id);ALTER TABLE communication_logs ENABLE ROW LEVEL SECURITY;CREATE POLICY "Org members can view communication logs" ON communication_logs FOR SELECT USING ((contract_id IS NOT NULL AND EXISTS (SELECT 1 FROM contracts WHERE id = communication_logs.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()))) OR (supplier_id IS NOT NULL AND EXISTS (SELECT 1 FROM suppliers WHERE id = communication_logs.supplier_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()))));CREATE POLICY "Org members can insert communication logs" ON communication_logs FOR INSERT WITH CHECK ((contract_id IS NOT NULL AND EXISTS (SELECT 1 FROM contracts WHERE id = communication_logs.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()))) OR (supplier_id IS NOT NULL AND EXISTS (SELECT 1 FROM suppliers WHERE id = communication_logs.supplier_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()))));CREATE POLICY "Org members can update communication logs" ON communication_logs FOR UPDATE USING ((contract_id IS NOT NULL AND EXISTS (SELECT 1 FROM contracts WHERE id = communication_logs.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()))) OR (supplier_id IS NOT NULL AND EXISTS (SELECT 1 FROM suppliers WHERE id = communication_logs.supplier_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()))));CREATE POLICY "Admins can delete communication logs" ON communication_logs FOR DELETE USING ((contract_id IS NOT NULL AND EXISTS (SELECT 1 FROM contracts WHERE id = communication_logs.contract_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin')) OR (supplier_id IS NOT NULL AND EXISTS (SELECT 1 FROM suppliers WHERE id = communication_logs.supplier_id AND organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin')));CREATE TABLE audit_logs(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),user_id uuid REFERENCES auth.users(id) ON DELETE SET NULL,organization_id uuid REFERENCES organizations(id) ON DELETE CASCADE NOT NULL,action text NOT NULL,entity_type text NOT NULL,entity_id uuid,old_value jsonb,new_value jsonb,ip_address inet,timestamp timestamp with time zone DEFAULT now() NOT NULL);CREATE INDEX idx_audit_logs_user_id ON audit_logs(user_id);CREATE INDEX idx_audit_logs_organization_id ON audit_logs(organization_id);ALTER TABLE audit_logs ENABLE ROW LEVEL SECURITY;CREATE POLICY "Admins can view audit logs for their org" ON audit_logs FOR SELECT USING (organization_id = (SELECT organization_id FROM profiles WHERE id = auth.uid()) AND (SELECT role FROM profiles WHERE id = auth.uid()) = 'admin');CREATE TABLE notifications(id uuid PRIMARY KEY DEFAULT uuid_generate_v4(),user_id uuid REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,message text NOT NULL,link text,is_read boolean DEFAULT FALSE NOT NULL,created_at timestamp with time zone DEFAULT now() NOT NULL);CREATE INDEX idx_notifications_user_id ON notifications(user_id);ALTER TABLE notifications ENABLE ROW LEVEL SECURITY;CREATE POLICY "Users can view their own notifications" ON notifications FOR SELECT USING (user_id = auth.uid());CREATE POLICY "Users can update their own notifications" ON notifications FOR UPDATE USING (user_id = auth.uid());CREATE POLICY "Org members can insert notifications for their org" ON notifications FOR INSERT WITH CHECK (EXISTS (SELECT 1 FROM profiles WHERE id = auth.uid() AND organization_id = (SELECT organization_id FROM profiles WHERE id = notifications.user_id)));CREATE POLICY "Users can delete their own notifications" ON notifications FOR DELETE USING (user_id = auth.uid());CREATE OR REPLACE FUNCTION update_updated_at_column() RETURNS TRIGGER AS $$ BEGIN NEW.updated_at = now(); RETURN NEW; END; $$ LANGUAGE plpgsql;CREATE TRIGGER update_profiles_updated_at BEFORE UPDATE ON profiles FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();CREATE TRIGGER update_suppliers_updated_at BEFORE UPDATE ON suppliers FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();CREATE TRIGGER update_contracts_updated_at BEFORE UPDATE ON contracts FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();CREATE TRIGGER update_tasks_updated_at BEFORE UPDATE ON tasks FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();CREATE TRIGGER update_approval_requests_updated_at BEFORE UPDATE ON approval_requests FOR EACH ROW EXECUTE FUNCTION update_updated_at_column();CREATE OR REPLACE FUNCTION public.handle_new_user() RETURNS TRIGGER AS $$ DECLARE org_id uuid; BEGIN INSERT INTO public.organizations (name) VALUES (NEW.email || ' Organization') RETURNING id INTO org_id; INSERT INTO public.profiles (id, organization_id, full_name, role) VALUES (NEW.id, org_id, NEW.raw_user_meta_data->>'full_name', 'admin'); RETURN NEW; END; $$ LANGUAGE plpgsql SECURITY DEFINER;CREATE TRIGGER on_auth_user_created AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();INSERT INTO storage.buckets (id, name, public) VALUES ('contract_documents', 'contract_documents', FALSE) ON CONFLICT (id) DO NOTHING;CREATE POLICY "Allow authenticated users to manage contract documents" ON storage.objects FOR ALL TO authenticated USING (bucket_id = 'contract_documents' AND auth.uid() IS NOT NULL);